previewCss:
.darma-loader-darma-custom-451 {color: var(--loader-color, #0284c7);
  --loader-secondary-color: var(--loader-secondary-color, #7dd3fc);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 35px;
   aspect-ratio: 1;
   border: 3px solid currentColor;
   animation: darma-loader-darma-custom-451-l1 2s infinite;
}
@keyframes darma-loader-darma-custom-451-l1  {
  0% {border-radius:50% 50% 0 0 }
25% {border-radius:0 50% 50% 0 }
50% {border-radius:0 0 50% 50%}
75% {border-radius:50% 0 0 50%}
100% {border-radius:50% 50% 0 0 }
}

